prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?idType ?idValue ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?idValue . BIND("normalizedId" AS ?idType) }
  OPTIONAL { ?model tai:originalId ?idValue . BIND("originalId" AS ?idType) }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(?idValue = "fbb0adafe6924f58ac902063a36646fe")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    (
      bound(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("fbb0adafe6924f58ac902063a36646fe"))
    ) || (
      bound(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("fbb0adafe6924f58ac902063a36646fe"))
    ) || CONTAINS(LCASE(STR(?model)), LCASE("fbb0adafe6924f58ac902063a36646fe"))
  )
}
LIMIT 25
